//! # aios-protocol — Canonical Agent OS Protocol
//!
//! This crate defines the shared types, event taxonomy, and trait interfaces
//! that all Agent OS projects (Arcan, Lago, Praxis, Autonomic) depend on.
//!
//! It is intentionally dependency-light (no runtime deps like tokio, axum, or redb)
//! so it can be used as a pure contract crate.
//!
//! ## Module Overview
//!
//! - [`ids`] — Typed ID wrappers (SessionId, EventId, BranchId, BlobHash, etc.)
//! - [`event`] — EventEnvelope + EventKind (~55 variants, forward-compatible)
//! - [`state`] — AgentStateVector, BudgetState (homeostasis vitals)
//! - [`mode`] — OperatingMode, GatingProfile (operating constraints)
//! - [`policy`] — Capability, PolicySet, PolicyEvaluation
//! - [`tool`] — ToolCall, ToolOutcome, ToolDefinition, ToolResult, Tool trait, ToolRegistry
//! - [`sandbox`] — SandboxTier, SandboxLimits, NetworkPolicy
//! - [`memory`] — SoulProfile, Observation, Provenance, MemoryScope
//! - [`session`] — SessionManifest, BranchInfo, CheckpointManifest
//! - [`ports`] — Runtime boundary ports (event store, provider, tools, policy, approvals, memory)
//! - [`error`] — KernelError, KernelResult

pub mod error;
pub mod event;
pub mod ids;
pub mod memory;
pub mod mode;
pub mod policy;
pub mod ports;
pub mod sandbox;
pub mod session;
pub mod state;
pub mod tool;

// Re-export the most commonly used types at the crate root.
pub use error::{KernelError, KernelResult};
pub use event::{
    ActorType, ApprovalDecision, EventActor, EventEnvelope, EventKind, EventRecord, EventSchema,
    LoopPhase, PolicyDecisionKind, RiskLevel, SnapshotType, SpanStatus, TokenUsage,
};
pub use ids::{
    AgentId, ApprovalId, BlobHash, BranchId, CheckpointId, EventId, MemoryId, RunId, SeqNo,
    SessionId, SnapshotId, ToolRunId,
};
pub use memory::{FileProvenance, MemoryScope, Observation, Provenance, SoulProfile};
pub use mode::{GatingProfile, OperatingMode};
pub use policy::{Capability, PolicyEvaluation, PolicySet};
pub use ports::{
    ApprovalPort, ApprovalRequest, ApprovalResolution, ApprovalTicket, EventRecordStream,
    EventStorePort, ModelCompletion, ModelCompletionRequest, ModelDirective, ModelProviderPort,
    ModelStopReason, PolicyGateDecision, PolicyGatePort, ToolExecutionReport, ToolExecutionRequest,
    ToolHarnessPort,
};
pub use sandbox::{NetworkPolicy, SandboxLimits, SandboxTier};
pub use session::{
    BranchInfo, BranchMergeResult, CheckpointManifest, ModelRouting, SessionManifest,
};
pub use state::{
    AgentStateVector, BlobRef, BudgetState, CanonicalState, MemoryNamespace, PatchApplyError,
    PatchOp, ProvenanceRef, StatePatch, VersionedCanonicalState,
};
pub use tool::{
    Tool, ToolAnnotations, ToolCall, ToolContent, ToolContext, ToolDefinition, ToolError,
    ToolOutcome, ToolRegistry, ToolResult,
};

//! Canonical event types for the Agent OS.
//!
//! Merges the best of three event models:
//! - Lago's `EventPayload` (35+ variants, forward-compatible deserializer)
//! - Arcan's `AgentEvent` (24 variants, runtime/streaming focused)
//! - aiOS's `EventKind` (40+ variants, homeostasis/voice/phases)
//!
//! Forward-compatible: unknown `"type"` tags deserialize into
//! `Custom { event_type, data }` instead of failing.

use crate::ids::*;
use crate::memory::MemoryScope;
use crate::mode::OperatingMode;
use crate::state::{AgentStateVector, BudgetState, StatePatch};
use serde::{Deserialize, Serialize};
use std::collections::HashMap;

/// Event actor identity.
#[derive(Debug, Clone, Serialize, Deserialize, PartialEq, Eq)]
#[serde(rename_all = "snake_case")]
pub enum ActorType {
    User,
    Agent,
    System,
}

/// Event actor metadata.
#[derive(Debug, Clone, Serialize, Deserialize, PartialEq, Eq)]
pub struct EventActor {
    #[serde(rename = "type")]
    pub actor_type: ActorType,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub component: Option<String>,
}

impl Default for EventActor {
    fn default() -> Self {
        Self {
            actor_type: ActorType::System,
            component: Some("arcan-daemon".to_owned()),
        }
    }
}

/// Event schema descriptor.
#[derive(Debug, Clone, Serialize, Deserialize, PartialEq, Eq)]
pub struct EventSchema {
    pub name: String,
    pub version: String,
}

impl Default for EventSchema {
    fn default() -> Self {
        Self {
            name: "aios-protocol".to_owned(),
            version: "0.1.0".to_owned(),
        }
    }
}

fn default_agent_id() -> AgentId {
    AgentId::default()
}

/// The universal state-change envelope for the Agent OS.
///
/// Adopts Lago's structure: typed IDs, branch-aware sequencing,
/// causal links, metadata bag, and schema versioning.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct EventEnvelope {
    pub event_id: EventId,
    pub session_id: SessionId,
    #[serde(default = "default_agent_id")]
    pub agent_id: AgentId,
    pub branch_id: BranchId,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub run_id: Option<RunId>,
    pub seq: SeqNo,
    /// Microseconds since UNIX epoch.
    #[serde(rename = "ts_ms", alias = "timestamp")]
    pub timestamp: u64,
    #[serde(default)]
    pub actor: EventActor,
    #[serde(default)]
    pub schema: EventSchema,
    #[serde(skip_serializing_if = "Option::is_none")]
    #[serde(rename = "parent_event_id", alias = "parent_id")]
    pub parent_id: Option<EventId>,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub trace_id: Option<String>,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub span_id: Option<String>,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub digest: Option<String>,
    pub kind: EventKind,
    #[serde(default)]
    pub metadata: HashMap<String, String>,
    #[serde(default = "default_schema_version")]
    pub schema_version: u8,
}

fn default_schema_version() -> u8 {
    1
}

impl EventEnvelope {
    /// Current time in microseconds since UNIX epoch.
    pub fn now_micros() -> u64 {
        std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .unwrap_or_default()
            .as_micros() as u64
    }
}

/// Convenience event record using `chrono::DateTime<Utc>` timestamps.
///
/// This is the type used by aiOS internal crates. It maps to `EventEnvelope`
/// for storage/streaming but uses ergonomic Rust types for construction.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct EventRecord {
    pub event_id: EventId,
    pub session_id: SessionId,
    #[serde(default = "default_agent_id")]
    pub agent_id: AgentId,
    pub branch_id: BranchId,
    pub sequence: SeqNo,
    pub timestamp: chrono::DateTime<chrono::Utc>,
    #[serde(default)]
    pub actor: EventActor,
    #[serde(default)]
    pub schema: EventSchema,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub causation_id: Option<EventId>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub correlation_id: Option<String>,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub trace_id: Option<String>,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub span_id: Option<String>,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub digest: Option<String>,
    pub kind: EventKind,
}

impl EventRecord {
    /// Create a new event record with the current timestamp.
    pub fn new(
        session_id: SessionId,
        branch_id: BranchId,
        sequence: SeqNo,
        kind: EventKind,
    ) -> Self {
        Self {
            event_id: EventId::default(),
            session_id,
            agent_id: AgentId::default(),
            branch_id,
            sequence,
            timestamp: chrono::Utc::now(),
            actor: EventActor::default(),
            schema: EventSchema::default(),
            causation_id: None,
            correlation_id: None,
            trace_id: None,
            span_id: None,
            digest: None,
            kind,
        }
    }

    /// Convert to the canonical `EventEnvelope` for storage/streaming.
    pub fn to_envelope(&self) -> EventEnvelope {
        EventEnvelope {
            event_id: self.event_id.clone(),
            session_id: self.session_id.clone(),
            agent_id: self.agent_id.clone(),
            branch_id: self.branch_id.clone(),
            run_id: None,
            seq: self.sequence,
            timestamp: self.timestamp.timestamp_micros() as u64,
            actor: self.actor.clone(),
            schema: self.schema.clone(),
            parent_id: self.causation_id.clone(),
            trace_id: self.trace_id.clone(),
            span_id: self.span_id.clone(),
            digest: self.digest.clone(),
            kind: self.kind.clone(),
            metadata: HashMap::new(),
            schema_version: 1,
        }
    }
}

// ─── Canonical EventKind ───────────────────────────────────────────

/// Discriminated union of ALL Agent OS event types.
///
/// This is the canonical taxonomy that all projects (Arcan, Lago, aiOS,
/// Autonomic) must use. Merges ~55 variants from three separate models.
///
/// Forward-compatible: unknown `"type"` tags deserialize into `Custom`.
#[derive(Debug, Clone, Serialize)]
#[non_exhaustive]
#[serde(tag = "type")]
pub enum EventKind {
    // ── Input / sensing ──
    UserMessage {
        content: String,
    },
    ExternalSignal {
        signal_type: String,
        data: serde_json::Value,
    },

    // ── Session lifecycle ──
    SessionCreated {
        name: String,
        config: serde_json::Value,
    },
    SessionResumed {
        #[serde(skip_serializing_if = "Option::is_none")]
        from_snapshot: Option<SnapshotId>,
    },
    SessionClosed {
        reason: String,
    },

    // ── Branch lifecycle ──
    BranchCreated {
        new_branch_id: BranchId,
        fork_point_seq: SeqNo,
        name: String,
    },
    BranchMerged {
        source_branch_id: BranchId,
        merge_seq: SeqNo,
    },

    // ── Loop phases (from aiOS) ──
    PhaseEntered {
        phase: LoopPhase,
    },
    DeliberationProposed {
        summary: String,
        #[serde(skip_serializing_if = "Option::is_none")]
        proposed_tool: Option<String>,
    },

    // ── Run lifecycle (from Lago + Arcan) ──
    RunStarted {
        provider: String,
        max_iterations: u32,
    },
    RunFinished {
        reason: String,
        total_iterations: u32,
        #[serde(skip_serializing_if = "Option::is_none")]
        final_answer: Option<String>,
        #[serde(skip_serializing_if = "Option::is_none")]
        usage: Option<TokenUsage>,
    },
    RunErrored {
        error: String,
    },

    // ── Step lifecycle (from Lago) ──
    StepStarted {
        index: u32,
    },
    StepFinished {
        index: u32,
        stop_reason: String,
        directive_count: usize,
    },

    // ── Text streaming (from Arcan + Lago) ──
    AssistantTextDelta {
        delta: String,
        #[serde(skip_serializing_if = "Option::is_none")]
        index: Option<u32>,
    },
    AssistantMessageCommitted {
        role: String,
        content: String,
        #[serde(skip_serializing_if = "Option::is_none")]
        model: Option<String>,
        #[serde(skip_serializing_if = "Option::is_none")]
        token_usage: Option<TokenUsage>,
    },
    TextDelta {
        delta: String,
        #[serde(skip_serializing_if = "Option::is_none")]
        index: Option<u32>,
    },
    Message {
        role: String,
        content: String,
        #[serde(skip_serializing_if = "Option::is_none")]
        model: Option<String>,
        #[serde(skip_serializing_if = "Option::is_none")]
        token_usage: Option<TokenUsage>,
    },

    // ── Tool lifecycle (merged from all three) ──
    ToolCallRequested {
        call_id: String,
        tool_name: String,
        arguments: serde_json::Value,
        #[serde(skip_serializing_if = "Option::is_none")]
        category: Option<String>,
    },
    ToolCallStarted {
        tool_run_id: ToolRunId,
        tool_name: String,
    },
    ToolCallCompleted {
        tool_run_id: ToolRunId,
        #[serde(skip_serializing_if = "Option::is_none")]
        call_id: Option<String>,
        tool_name: String,
        result: serde_json::Value,
        duration_ms: u64,
        status: SpanStatus,
    },
    ToolCallFailed {
        call_id: String,
        tool_name: String,
        error: String,
    },

    // ── File operations (from Lago) ──
    FileWrite {
        path: String,
        blob_hash: BlobHash,
        size_bytes: u64,
        #[serde(skip_serializing_if = "Option::is_none")]
        content_type: Option<String>,
    },
    FileDelete {
        path: String,
    },
    FileRename {
        old_path: String,
        new_path: String,
    },
    FileMutated {
        path: String,
        content_hash: String,
    },

    // ── State management (from Lago + Arcan) ──
    StatePatchCommitted {
        new_version: u64,
        patch: StatePatch,
    },
    StatePatched {
        #[serde(skip_serializing_if = "Option::is_none")]
        index: Option<u32>,
        patch: serde_json::Value,
        revision: u64,
    },
    ContextCompacted {
        dropped_count: usize,
        tokens_before: usize,
        tokens_after: usize,
    },

    // ── Policy (from Lago) ──
    PolicyEvaluated {
        tool_name: String,
        decision: PolicyDecisionKind,
        #[serde(skip_serializing_if = "Option::is_none")]
        rule_id: Option<String>,
        #[serde(skip_serializing_if = "Option::is_none")]
        explanation: Option<String>,
    },

    // ── Approval gate (from Lago + Arcan + aiOS) ──
    ApprovalRequested {
        approval_id: ApprovalId,
        call_id: String,
        tool_name: String,
        arguments: serde_json::Value,
        risk: RiskLevel,
    },
    ApprovalResolved {
        approval_id: ApprovalId,
        decision: ApprovalDecision,
        #[serde(skip_serializing_if = "Option::is_none")]
        reason: Option<String>,
    },

    // ── Snapshots (from Lago) ──
    SnapshotCreated {
        snapshot_id: SnapshotId,
        snapshot_type: SnapshotType,
        covers_through_seq: SeqNo,
        data_hash: BlobHash,
    },

    // ── Sandbox lifecycle (from Lago) ──
    SandboxCreated {
        sandbox_id: String,
        tier: String,
        config: serde_json::Value,
    },
    SandboxExecuted {
        sandbox_id: String,
        command: String,
        exit_code: i32,
        duration_ms: u64,
    },
    SandboxViolation {
        sandbox_id: String,
        violation_type: String,
        details: String,
    },
    SandboxDestroyed {
        sandbox_id: String,
    },

    // ── Memory (from Lago) ──
    ObservationAppended {
        scope: MemoryScope,
        observation_ref: BlobHash,
        #[serde(skip_serializing_if = "Option::is_none")]
        source_run_id: Option<String>,
    },
    ReflectionCompacted {
        scope: MemoryScope,
        summary_ref: BlobHash,
        covers_through_seq: SeqNo,
    },
    MemoryProposed {
        scope: MemoryScope,
        proposal_id: MemoryId,
        entries_ref: BlobHash,
        #[serde(skip_serializing_if = "Option::is_none")]
        source_run_id: Option<String>,
    },
    MemoryCommitted {
        scope: MemoryScope,
        memory_id: MemoryId,
        committed_ref: BlobHash,
        #[serde(skip_serializing_if = "Option::is_none")]
        supersedes: Option<MemoryId>,
    },
    MemoryTombstoned {
        scope: MemoryScope,
        memory_id: MemoryId,
        reason: String,
    },

    // ── Homeostasis (from aiOS) ──
    Heartbeat {
        summary: String,
        #[serde(skip_serializing_if = "Option::is_none")]
        checkpoint_id: Option<CheckpointId>,
    },
    StateEstimated {
        state: AgentStateVector,
        mode: OperatingMode,
    },
    BudgetUpdated {
        budget: BudgetState,
        reason: String,
    },
    ModeChanged {
        from: OperatingMode,
        to: OperatingMode,
        reason: String,
    },
    GatesUpdated {
        gates: serde_json::Value,
        reason: String,
    },
    CircuitBreakerTripped {
        reason: String,
        error_streak: u32,
    },

    // ── Checkpoints (from aiOS) ──
    CheckpointCreated {
        checkpoint_id: CheckpointId,
        event_sequence: u64,
        state_hash: String,
    },
    CheckpointRestored {
        checkpoint_id: CheckpointId,
        restored_to_seq: u64,
    },

    // ── Voice (from aiOS) ──
    VoiceSessionStarted {
        voice_session_id: String,
        adapter: String,
        model: String,
        sample_rate_hz: u32,
        channels: u8,
    },
    VoiceInputChunk {
        voice_session_id: String,
        chunk_index: u64,
        bytes: usize,
        format: String,
    },
    VoiceOutputChunk {
        voice_session_id: String,
        chunk_index: u64,
        bytes: usize,
        format: String,
    },
    VoiceSessionStopped {
        voice_session_id: String,
        reason: String,
    },
    VoiceAdapterError {
        voice_session_id: String,
        message: String,
    },

    // ── World models (new, forward-looking) ──
    WorldModelObserved {
        state_ref: BlobHash,
        meta: serde_json::Value,
    },
    WorldModelRollout {
        trajectory_ref: BlobHash,
        #[serde(skip_serializing_if = "Option::is_none")]
        score: Option<f32>,
    },

    // ── Intent lifecycle (new) ──
    IntentProposed {
        intent_id: String,
        kind: String,
        #[serde(skip_serializing_if = "Option::is_none")]
        risk: Option<RiskLevel>,
    },
    IntentEvaluated {
        intent_id: String,
        allowed: bool,
        requires_approval: bool,
        #[serde(default)]
        reasons: Vec<String>,
    },
    IntentApproved {
        intent_id: String,
        #[serde(default, skip_serializing_if = "Option::is_none")]
        actor: Option<String>,
    },
    IntentRejected {
        intent_id: String,
        #[serde(default)]
        reasons: Vec<String>,
    },

    // ── Error ──
    ErrorRaised {
        message: String,
    },

    // ── Forward-compatible catch-all ──
    Custom {
        event_type: String,
        data: serde_json::Value,
    },
}

// ─── Supporting types ──────────────────────────────────────────────

/// Agent loop phase (from aiOS).
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum LoopPhase {
    Perceive,
    Deliberate,
    Gate,
    Execute,
    Commit,
    Reflect,
    Sleep,
}

/// Token usage reported by LLM providers.
#[derive(Debug, Clone, Copy, Default, PartialEq, Eq, Serialize, Deserialize)]
pub struct TokenUsage {
    #[serde(default)]
    pub prompt_tokens: u32,
    #[serde(default)]
    pub completion_tokens: u32,
    #[serde(default)]
    pub total_tokens: u32,
}

/// Tool execution span status.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum SpanStatus {
    Ok,
    Error,
    Timeout,
    Cancelled,
}

/// Risk level for policy evaluation. Includes Critical from Lago.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum RiskLevel {
    Low,
    Medium,
    High,
    Critical,
}

/// Approval decision outcome.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum ApprovalDecision {
    Approved,
    Denied,
    Timeout,
}

/// Snapshot type.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum SnapshotType {
    Full,
    Incremental,
}

/// Policy decision kind.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum PolicyDecisionKind {
    Allow,
    Deny,
    RequireApproval,
}

// ─── Forward-compatible deserializer ───────────────────────────────

/// Internal helper enum for the forward-compatible deserializer.
/// Mirrors EventKind exactly but derives Deserialize.
#[derive(Deserialize)]
#[serde(tag = "type")]
enum EventKindKnown {
    UserMessage {
        content: String,
    },
    ExternalSignal {
        signal_type: String,
        data: serde_json::Value,
    },
    SessionCreated {
        name: String,
        config: serde_json::Value,
    },
    SessionResumed {
        #[serde(default)]
        from_snapshot: Option<SnapshotId>,
    },
    SessionClosed {
        reason: String,
    },
